   159→
   160→	if newObj != nil {
   161→		var err error
   162→		indexValues, err = indexFunc(newObj)
   163→		if err != nil {
   164→			panic(fmt.Errorf("unable to calculate an index entry for key %q on index %q: %v", key, name, err))
