   114→func (i *storeIndex) getIndexValues(indexName string) []string {
   115→	index := i.indices[indexName]
   116→	names := make([]string, 0, len(index))
   117→	for key := range index {
   118→		names = append(names, key)
   119→	}
   120→	return names
   121→}
