   272→func (c *threadSafeMap) ListKeys() []string {
   273→	c.lock.RLock()
   274→	defer c.lock.RUnlock()
   275→	list := make([]string, 0, len(c.items))
   276→	for key := range c.items {
   277→		list = append(list, key)
   278→	}
   279→	return list
   280→}
   281→
